python3 -c "
import json

splits = ['train', 'val', 'test']
for split in splits:
    path = f'/local/nick/ai_iree/dataset0211/{split}/patterns.json'
    try:
        with open(path) as f:
            data = json.load(f)
        print(f'\n{split}/patterns.json:')
        for k in ['named_ops', 'generic_ops', 'fused_ops']:
            if k in data:
                n = len(data[k])
                print(f'  {k}: {n} entries')
                if k == 'fused_ops' and n > 0:
                    print(f'    hash keys: {list(data[k].keys())}')
    except FileNotFoundError:
        print(f'\n{split}/patterns.json: NOT FOUND')
    except Exception as e:
        print(f'\n{split}/patterns.json: ERROR - {e}')
"
